queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?action_movies a :Action_Movies .
    ?action_movies p:Title ?title .
    ?action_movies p:Stars ?stars_f .
    FILTER(STR(?stars_f) = "Leonardo DiCaprio")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?adventure_movies a :Adventure_Movies .
    ?adventure_movies p:Title ?title .
    ?adventure_movies p:Stars ?stars_f .
    FILTER(STR(?stars_f) = "Leonardo DiCaprio")
    BIND(?title AS ?o0)
  }
}

